export function rowSelectLinkWithoutParents(state) {
    const removeParents = (parent, node, key) => {
        const nodeWithoutParent = { ...node };
        delete nodeWithoutParent.parent;
        parent.children?.set(key, nodeWithoutParent);
        if (node.children) {
            nodeWithoutParent.children = new Map();
            node.children.forEach((x, k) => removeParents(nodeWithoutParent, x, k));
        }
    };
    const root = { ...state, children: new Map() };
    state.children.forEach((x, k) => removeParents(root, x, k));
    return root;
}
